"use client";

import type { SVGProps } from "react";

import styles from "./center-circle-motion.module.css";

export interface CenterCircleMotionProps extends Omit<SVGProps<SVGSVGElement>, "title"> {
  isAnimated?: boolean;
  size?: number;
  title?: string | null;
}

export function CenterCircleMotion({
  className,
  isAnimated = false,
  size = 32,
  title = "Center circle",
  ...props
}: CenterCircleMotionProps) {
  const hasAccessibleName = Boolean(title || props["aria-label"] || props["aria-labelledby"]);

  return (
    <svg
      fill="currentColor"
      {...props}
      aria-hidden={hasAccessibleName ? props["aria-hidden"] : true}
      className={[isAnimated ? styles.isAnimating : "", className].filter(Boolean).join(" ")}
      height={size}
      role={props.role ?? (hasAccessibleName ? "img" : undefined)}
      viewBox="0 0 32 32"
      width={size}
    >
      {title ? <title>{title}</title> : null}
      <path
        className={styles.CenterCircle}
        d="M27,16c0,6.1-4.9,11-11,11S5,22.1,5,16S9.9,5,16,5S27,9.9,27,16z"
        fill="none"
        stroke="currentColor"
      />
      <path className={styles.CenterCircleTop} d="M17,2h-2v8h2V2z" />
      <path className={styles.CenterCircleRight} d="M10.1,17v-2h-8v2H10.1z" />
      <path className={styles.CenterCircleBottom} d="M15,29.9h2v-8h-2V29.9z" />
      <path className={styles.CenterCircleLeft} d="M29.9,17v-2h-8v2H29.9z" />
      <path d="M29.9,17v-2h-8v2H29.9z M15,29.9h2v-8h-2V29.9z M10.1,17v-2h-8v2H10.1z M17,2h-2v8h2V2z" />
    </svg>
  );
}

.CenterCircle {
  stroke-miterlimit: 10;
  stroke-width: 2px;
  transform-origin: 1rem 1rem;
  vector-effect: non-scaling-stroke;
  will-change: transform;
}

.CenterCircleTop,
.CenterCircleRight,
.CenterCircleLeft,
.CenterCircleBottom {
  will-change: transform;
}

.isAnimating .CenterCircle {
  animation: center-circle 280ms cubic-bezier(0.4, 0.14, 0.3, 1);
}

.isAnimating .CenterCircleTop {
  animation: center-circle-top 280ms cubic-bezier(0.4, 0.14, 0.3, 1);
}

.isAnimating .CenterCircleRight {
  animation: center-circle-right 280ms cubic-bezier(0.4, 0.14, 0.3, 1);
}

.isAnimating .CenterCircleLeft {
  animation: center-circle-left 280ms cubic-bezier(0.4, 0.14, 0.3, 1);
}

.isAnimating .CenterCircleBottom {
  animation: center-circle-bottom 280ms cubic-bezier(0.4, 0.14, 0.3, 1);
}

@keyframes center-circle {
  0% { transform: scale(1); }
  50% { transform: scale(0.8); }
  100% { transform: scale(1); }
}

@keyframes center-circle-top {
  0% { transform: translateY(0); }
  50% { transform: translateY(2px); }
  100% { transform: translateY(0); }
}

@keyframes center-circle-bottom {
  0% { transform: translateY(0); }
  50% { transform: translateY(-2px); }
  100% { transform: translateY(0); }
}

@keyframes center-circle-right {
  0% { transform: translateX(0); }
  50% { transform: translateX(2px); }
  100% { transform: translateX(0); }
}

@keyframes center-circle-left {
  0% { transform: translateX(0); }
  50% { transform: translateX(-2px); }
  100% { transform: translateX(0); }
}

@media (prefers-reduced-motion: reduce) {
  .isAnimating .CenterCircle,
  .isAnimating .CenterCircleTop,
  .isAnimating .CenterCircleRight,
  .isAnimating .CenterCircleLeft,
  .isAnimating .CenterCircleBottom {
    animation: none;
  }
}
